const rawWorkflows = $input.first().json.data || [];
// Wir filtern Leichen und machen daraus einzelne n8n-Aufgaben
return rawWorkflows
  .filter(w => w.id && w.name)
  .map(w => ({ json: w }));

function hashString(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash |= 0;
  }
  return hash.toString();
}

const wf = $json; 

// 1. Namen sicher extrahieren (n8n API liefert ihn auf oberster Ebene)
const wfId = (wf.id || '0').toString();
const wfName = wf.name || wf.id || 'Unnamed Workflow';

function sortObj(obj) {
  if (obj === null || typeof obj !== 'object') return obj;
  if (Array.isArray(obj)) return obj.map(sortObj);
  return Object.keys(obj).sort().reduce((acc, key) => {
    // Diese Felder ignorieren wir für den Vergleich, da sie sich ständig ändern
    if (['id', 'updatedAt', 'createdAt', 'versionId'].includes(key)) return acc;
    acc[key] = sortObj(obj[key]);
    return acc;
  }, {});
}

// 2. Workflow normalisieren & Hashen
const wfClean = sortObj({
  name: wfName,
  nodes: wf.nodes || [],
  connections: wf.connections || {},
  settings: wf.settings || {},
  active: wf.active === true
});

// Gespeichert wird MIT id (damit Sync-Workflow den Workflow zuordnen kann)
const wfStore = Object.assign({ id: wfId }, wfClean);
const contentBase64 = Buffer.from(JSON.stringify(wfStore)).toString('base64');

// Hash MUSS auf wfStore basieren (mit id), da GitHub genau diesen Inhalt speichert
const jsonString = JSON.stringify(wfStore);
const localHash = hashString(jsonString);

// Dateinamen sicher machen (/ und : ersetzen)
const safeName = wfName.replace(/[\/:\\]/g, '-');

// PFAD: n8n/ID/Workflow-Name.json
const finalPath = `n8n/${wfId}/${safeName}.json`;

return {
  id: wfId,
  name: wfName,
  filepath: finalPath,
  localContent: contentBase64,
  localHash: localHash,
  message: `🤖 Auto-Backup: ${wfName} (ID: ${wfId})`
};

const items = $input.all();
// Initialisierung mit 0 stellt sicher, dass Felder nie leer/undefined sind
let erfolgreich = 0;
let übersprungen = 0;
let fehlerhaft = 0;

for (const item of items) {
    const status = item.json.status;
    if (status === 'success') erfolgreich++;
    else if (status === 'skip') übersprungen++;
    else if (status === 'error') fehlerhaft++;
}

const now = new Date();
const timezone = 'Europe/Berlin';
const tag = now.toLocaleDateString('de-DE', { timeZone: timezone, day: '2-digit' });
const monat = now.toLocaleDateString('de-DE', { timeZone: timezone, month: '2-digit' });
const jahr = now.toLocaleDateString('de-DE', { timeZone: timezone, year: 'numeric' });
const datum = tag + '.' + monat + '.' + jahr;

return [{

    json: {
        erfolgreich,
        übersprungen,
        fehlerhaft,
        gesamt: erfolgreich + übersprungen + fehlerhaft,
        datum
    }
}];

const githubData = $input.first();
const localData = $('Workflow extrahieren').first().json;
const githubSha = githubData?.json?.sha || null;

function sortObj(obj) {
  if (obj === null || typeof obj !== 'object') return obj;
  if (Array.isArray(obj)) return obj.map(sortObj);
  return Object.keys(obj).sort().reduce((acc, key) => {
    if (['id', 'updatedAt', 'createdAt', 'versionId'].includes(key)) return acc;
    acc[key] = sortObj(obj[key]);
    return acc;
  }, {});
}

function hashString(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash |= 0;
  }
  return hash.toString();
}

let action;
let httpBody;

if (!githubSha) {
  action = 'create';
  httpBody = {
    message: localData.message,
    content: localData.localContent
  };
} else {
  const rawContent = githubData.json.content || '';
  let remoteObj = null;

  // Versuch 1: base64 dekodieren (GitHub API Standard)
  try {
    const cleaned = rawContent.replace(/[\n\r]/g, '');
    const decoded = Buffer.from(cleaned, 'base64').toString('utf8');
    remoteObj = JSON.parse(decoded);
  } catch (e) {
    // Versuch 2: Content bereits dekodiert (n8n GitHub-Node)
    try {
      remoteObj = JSON.parse(typeof rawContent === 'string' ? rawContent : JSON.stringify(rawContent));
    } catch (e2) {
      remoteObj = null;
    }
  }

  if (remoteObj) {
    // Gleiche Normalisierung wie in 'Workflow extrahieren'
    const remoteClean = sortObj({
      name: remoteObj.name || '',
      nodes: remoteObj.nodes || [],
      connections: remoteObj.connections || {},
      settings: remoteObj.settings || {},
      active: remoteObj.active === true
    });
    const remoteStore = Object.assign({ id: (remoteObj.id || '0').toString() }, remoteClean);
    const remoteHash = hashString(JSON.stringify(remoteStore));

    if (localData.localHash === remoteHash) {
      action = 'skip';
      httpBody = null;
    } else {
      action = 'update';
      httpBody = {
        message: localData.message,
        content: localData.localContent,
        sha: githubSha
      };
    }
  } else {
    action = 'update';
    httpBody = {
      message: localData.message,
      content: localData.localContent,
      sha: githubSha
    };
  }
}

return {
  action,
  filepath: localData.filepath,
  name: localData.name,
  httpBody
};
